import{_ as t,a as e,b as i,c as d,d as n,e as r}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as p,o as s,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"IP 位置情報とユーザー管理","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/ip-geolocation-and-user-management.md","filePath":"ja-JP/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ja-JP/Other/ip-geolocation-and-user-management.md"};function h(m,a,u,b,g,_){return s(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="ip-位置情報とユーザー管理" tabindex="-1">IP 位置情報とユーザー管理 <a class="header-anchor" href="#ip-位置情報とユーザー管理" aria-label="Permalink to &quot;IP 位置情報とユーザー管理&quot;">​</a></h1><p>IP 位置情報は、アップロード記録やログイン端末などに残る IP アドレスを、おおよその地域情報へ変換します。</p><p>設定しておくと、管理画面でアップロード元やアクセス元を把握しやすくなります。ユーザー管理では、不審な IP のアップロードを停止したり、再開したりできます。</p><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定 -&gt; IP 位置情報</span></span></code></pre></div><p><img src="'+t+`" alt="IP 位置情報" loading="lazy"></p><h2 id="設定できる項目" tabindex="-1">設定できる項目 <a class="header-anchor" href="#設定できる項目" aria-label="Permalink to &quot;設定できる項目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>IP 位置情報の言語</td><td>日本語、英語、中国語など、表示言語を選びます</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service 用のアカウント ID</td></tr><tr><td>MaxMind License Key</td><td>MaxMind のライセンスキー</td></tr><tr><td>Tencent Map Key</td><td>中国大陸向け住所表示に強い Tencent 位置情報サービス</td></tr><tr><td>ipapi Key</td><td>多言語表示に対応した APILayer ipapi のキー</td></tr></tbody></table><p>必要なサービスだけ設定すれば構いません。何も設定していない場合でも内蔵の無料取得元を試しますが、安定性や精度は自分で設定したサービスの方が高くなります。</p><h2 id="日本語表示で使う場合" tabindex="-1">日本語表示で使う場合 <a class="header-anchor" href="#日本語表示で使う場合" aria-label="Permalink to &quot;日本語表示で使う場合&quot;">​</a></h2><p>日本語の位置表示を重視する場合は、言語を日本語にし、MaxMind または ipapi を設定するのがおすすめです。中国大陸の IP を細かく見たい場合は Tencent Map Key も追加します。</p><h2 id="maxmind-の設定" tabindex="-1">MaxMind の設定 <a class="header-anchor" href="#maxmind-の設定" aria-label="Permalink to &quot;MaxMind の設定&quot;">​</a></h2><p>MaxMind では次の 2 つを用意します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>ダッシュボードで Account ID を確認し、License Keys からキーを作成して ImgBed に貼り付けます。</p><p><img src="`+e+'" alt="MaxMind キー設定" loading="lazy"></p><h2 id="ipapi-の設定" tabindex="-1">ipapi の設定 <a class="header-anchor" href="#ipapi-の設定" aria-label="Permalink to &quot;ipapi の設定&quot;">​</a></h2><p>ipapi のコンソールで API Key をコピーし、ImgBed の <code>ipapi Key</code> に貼り付けます。</p><p><img src="'+i+'" alt="ipapi 設定" loading="lazy"></p><h2 id="ユーザー管理で見ること" tabindex="-1">ユーザー管理で見ること <a class="header-anchor" href="#ユーザー管理で見ること" aria-label="Permalink to &quot;ユーザー管理で見ること&quot;">​</a></h2><p>ユーザー管理は管理画面上部から開けます。</p><p><img src="'+d+'" alt="ユーザー管理" loading="lazy"></p><p>IP ごとに次の情報を確認できます。</p><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>IP</td><td>アップロード元の IP</td></tr><tr><td>位置</td><td>解析されたおおよその地域</td></tr><tr><td>合計アップロードサイズ</td><td>その IP がアップロードした合計容量</td></tr><tr><td>アップロード数</td><td>アップロード回数</td></tr><tr><td>アップロード許可</td><td>オフにすると以後のアップロードを拒否します</td></tr></tbody></table><p>左側の矢印を開くと、その IP がアップロードしたファイル一覧を確認できます。ファイル名、プレビュー、サイズ、審査結果、状態、アップロード時刻を見て判断できます。</p><p><img src="'+n+'" alt="高度なフィルタ" loading="lazy"></p><h2 id="運用のポイント" tabindex="-1">運用のポイント <a class="header-anchor" href="#運用のポイント" aria-label="Permalink to &quot;運用のポイント&quot;">​</a></h2><ul><li>不審な IP は、ファイル内容を確認してからアップロード許可をオフにします。</li><li>高頻度アップロードや大容量アップロードは、並び替えと検索で確認できます。</li><li>位置情報はあくまで推定です。判断材料の 1 つとして使ってください。</li></ul><p><img src="'+r+'" alt="モバイル表示" loading="lazy"></p>',29)])])}const M=p(c,[["render",h]]);export{I as __pageData,M as default};
